import React, { useState } from 'react';
import { Search, Info } from 'lucide-react';
import { FOOD_DATABASE } from '../constants';
import { FoodItem } from '../types';

const Diet: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredFood = FOOD_DATABASE.filter(item => 
    item.name.includes(searchTerm)
  );

  const getPurineColor = (level: string) => {
    switch(level) {
      case 'low': return 'bg-success text-white';
      case 'medium': return 'bg-warning text-white';
      case 'high': return 'bg-danger text-white';
      default: return 'bg-slate-200';
    }
  };

  const getPurineLabel = (level: string) => {
    switch(level) {
      case 'low': return '低嘌呤 (绿灯)';
      case 'medium': return '中嘌呤 (黄灯)';
      case 'high': return '高嘌呤 (红灯)';
      default: return '未知';
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
          <div>
            <h3 className="text-lg font-bold text-slate-800">食物嘌呤查询</h3>
            <p className="text-sm text-slate-500">输入食物名称，快速判断是否可食用</p>
          </div>
          <div className="relative w-full md:w-64">
            <input
              type="text"
              placeholder="例如：牛肉、豆腐..."
              className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
            <Search className="absolute left-3 top-2.5 text-slate-400" size={18} />
          </div>
        </div>

        {/* Legend */}
        <div className="flex gap-4 mb-6 text-xs text-slate-600 bg-slate-50 p-3 rounded-lg">
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-success"></div>
            <span>放心吃 (低)</span>
          </div>
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-warning"></div>
            <span>适量吃 (中)</span>
          </div>
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-danger"></div>
            <span>避免吃 (高)</span>
          </div>
        </div>

        {/* List */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {filteredFood.map((food) => (
            <div key={food.id} className="flex items-center justify-between p-4 border border-slate-100 rounded-xl hover:shadow-md transition-shadow">
              <div>
                <h4 className="font-bold text-slate-800">{food.name}</h4>
                <p className="text-xs text-slate-400 mt-1">{food.purineValue} mg/100g</p>
              </div>
              <span className={`px-3 py-1 rounded-full text-xs font-bold shadow-sm ${getPurineColor(food.purineLevel)}`}>
                {food.purineLevel === 'low' && '绿灯行'}
                {food.purineLevel === 'medium' && '黄灯缓'}
                {food.purineLevel === 'high' && '红灯停'}
              </span>
            </div>
          ))}
          {filteredFood.length === 0 && (
            <div className="col-span-full py-10 text-center text-slate-400">
              未找到相关食物，试试其他关键词
            </div>
          )}
        </div>
      </div>

      <div className="bg-gradient-to-r from-blue-50 to-indigo-50 p-6 rounded-2xl border border-blue-100 flex items-start gap-4">
        <div className="p-2 bg-white rounded-lg shadow-sm text-primary-600">
          <Info size={24} />
        </div>
        <div>
          <h4 className="font-bold text-primary-800 mb-2">饮食小贴士</h4>
          <p className="text-sm text-primary-700 leading-relaxed">
            控制嘌呤摄入是预防痛风发作的关键。建议每日饮水 2000ml 以上，促进尿酸排泄。
            避免饮用含糖饮料和酒精，特别是啤酒。
          </p>
        </div>
      </div>
    </div>
  );
};

export default Diet;

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles } from 'lucide-react';

interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
}

const AIChat: React.FC = () => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: 'model',
      text: '您好，我是您的痛风管理智能助手。我可以为您分析尿酸趋势、提供饮食建议或解答用药疑问。请问今天有什么可以帮您？'
    }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    // Simulation of AI response (In a real app, this would use the Gemini API)
    setTimeout(() => {
      let responseText = "我明白了。作为您的健康助手，建议您保持每日饮水量在2000ml以上。";

      if (input.includes('疼')) {
        responseText = "如果您感到关节疼痛，请立即停止运动并抬高患肢。如果疼痛剧烈（超过5分），建议服用您医生开具的止痛药（如依托考昔），并及时就医。需要我帮您记录这次发作吗？";
      } else if (input.includes('吃') || input.includes('食')) {
        responseText = "关于饮食，建议您遵循'低嘌呤'原则。多吃新鲜蔬菜（如西兰花、白菜），少吃内脏、海鲜和肉汤。您刚才想查询具体的食物吗？";
      }

      const aiMsg: Message = { 
        id: (Date.now() + 1).toString(), 
        role: 'model', 
        text: responseText 
      };
      setMessages(prev => [...prev, aiMsg]);
      setIsLoading(false);
    }, 1500);
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-slate-100 h-[calc(100vh-200px)] flex flex-col overflow-hidden">
      {/* Chat Header */}
      <div className="bg-gradient-to-r from-primary-600 to-indigo-600 p-4 text-white flex items-center gap-3">
        <div className="p-2 bg-white/20 rounded-lg">
           <Sparkles size={20} className="text-yellow-300" />
        </div>
        <div>
           <h3 className="font-bold">智能医生助手</h3>
           <p className="text-xs text-blue-100">Powered by Gemini AI</p>
        </div>
      </div>

      {/* Messages Area */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50/50">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex max-w-[80%] gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${
                msg.role === 'user' ? 'bg-slate-200' : 'bg-primary-100'
              }`}>
                {msg.role === 'user' ? <User size={16} className="text-slate-600" /> : <Bot size={16} className="text-primary-600" />}
              </div>
              <div className={`p-4 rounded-2xl text-sm leading-relaxed shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-primary-600 text-white rounded-tr-none' 
                  : 'bg-white text-slate-700 border border-slate-100 rounded-tl-none'
              }`}>
                {msg.text}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
             <div className="flex max-w-[80%] gap-3">
               <div className="w-8 h-8 rounded-full bg-primary-100 flex items-center justify-center flex-shrink-0">
                 <Bot size={16} className="text-primary-600" />
               </div>
               <div className="bg-white p-4 rounded-2xl rounded-tl-none border border-slate-100 shadow-sm flex items-center gap-2">
                 <div className="w-2 h-2 bg-primary-400 rounded-full animate-bounce"></div>
                 <div className="w-2 h-2 bg-primary-400 rounded-full animate-bounce delay-100"></div>
                 <div className="w-2 h-2 bg-primary-400 rounded-full animate-bounce delay-200"></div>
               </div>
             </div>
          </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white border-t border-slate-100">
        <div className="relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyPress}
            placeholder="输入您的问题，例如：'尿酸450需要吃药吗？'"
            className="w-full pl-4 pr-12 py-4 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-primary-500 focus:bg-white transition-all shadow-inner"
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || isLoading}
            className="absolute right-2 top-2 p-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors shadow-md"
          >
            <Send size={20} />
          </button>
        </div>
        <p className="text-xs text-center text-slate-400 mt-2">
          AI 建议仅供参考，不能替代专业医疗诊断。
        </p>
      </div>
    </div>
  );
};

export default AIChat;

