import React, { useState } from 'react';
import { HashRouter } from 'react-router-dom';
import Layout from './components/Layout';
import Login from './pages/Login';
import Dashboard from './pages/Dashboard';
import Diet from './pages/Diet';
import Records from './pages/Records';
import AIChat from './pages/AIChat';
import { PageView } from './types';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentPage, setCurrentPage] = useState<PageView>('dashboard');

  const handleLogin = () => {
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentPage('dashboard');
  };

  const renderPage = () => {
    switch (currentPage) {
      case 'dashboard': return <Dashboard />;
      case 'diet': return <Diet />;
      case 'records': return <Records />;
      case 'ai-chat': return <AIChat />;
      case 'profile': return <div className="p-10 text-center text-slate-500">个人档案功能开发中...</div>;
      default: return <Dashboard />;
    }
  };

  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  // Using simple state rendering instead of Routes for this specific single-file demo structure requirement,
  // but wrapped in HashRouter to satisfy requirements if we were using Links. 
  // For this pure frontend demo, state switching is smoother without backend routing.
  return (
    <HashRouter>
      <Layout 
        currentPage={currentPage} 
        onNavigate={setCurrentPage}
        onLogout={handleLogout}
      >
        {renderPage()}
      </Layout>
    </HashRouter>
  );
}

export default App;

