import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles } from 'lucide-react';
import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
}

const AIChat: React.FC = () => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: 'model',
      text: '您好，我是您的痛风管理智能助手。我可以为您分析尿酸趋势、提供饮食建议或解答用药疑问。请问今天有什么可以帮您？'
    }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Initialize Gemini
  // NOTE: In a production web app, it is safer to call a backend which calls the API. 
  // For this frontend-only demo, we use the key directly as requested.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userText = input;
    const userMsg: Message = { id: Date.now().toString(), role: 'user', text: userText };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      // Create a temporary ID for the streaming message
      const responseId = (Date.now() + 1).toString();
      let fullResponseText = "";

      // Add placeholder message
      setMessages(prev => [...prev, { id: responseId, role: 'model', text: '' }]);

      const model = 'gemini-2.5-flash';
      const systemInstruction = `You are a professional medical assistant for a Gout/Hyperuricemia management platform called "GoutCare". 
      Your tone is empathetic, professional, and encouraging.
      You provide advice based on clinical guidelines for Gout (low purine diet, hydration, medication adherence like Febuxostat).

      Key responsibilities:
      1. Diet advice: Use the "Traffic Light" system (Red: High Purine, Yellow: Medium, Green: Low).
      2. Symptom analysis: If user mentions pain, ask about location (big toe, knee) and pain level (1-10). Suggest rest and hydration.
      3. Disclaimer: ALWAYS include a brief disclaimer that you are an AI and not a doctor when giving medical advice.

      Language: Chinese (Simplified).
      Keep responses concise and easy to read on a screen.`;

      // Use generateContentStream for a direct response
      // Ideally we would use chats.create to maintain history, but for simplicity we'll send context if needed or just single turn here.
      // To maintain history properly in a frontend demo without backend persistence is tricky, 
      // but we can pass previous messages. For this demo, we'll start a fresh chat or send history.

      // Construct history for the API
      const history = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));
      // Add current user message
      history.push({ role: 'user', parts: [{ text: userText }]});

      const chat = ai.chats.create({
        model: model,
        config: { systemInstruction },
        history: messages.map(m => ({ role: m.role, parts: [{ text: m.text }] }))
      });

      const result = await chat.sendMessageStream({ message: userText });

      for await (const chunk of result) {
        const c = chunk as GenerateContentResponse;
        if (c.text) {
          fullResponseText += c.text;
          setMessages(prev => 
            prev.map(msg => 
              msg.id === responseId ? { ...msg, text: fullResponseText } : msg
            )
          );
        }
      }

    } catch (error) {
      console.error("Gemini API Error:", error);
      setMessages(prev => [...prev, { 
        id: Date.now().toString(), 
        role: 'model', 
        text: "抱歉，由于网络原因，我现在无法回答。请稍后再试。" 
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-slate-100 h-[calc(100vh-200px)] flex flex-col overflow-hidden">
      {/* Chat Header */}
      <div className="bg-gradient-to-r from-primary-600 to-indigo-600 p-4 text-white flex items-center gap-3">
        <div className="p-2 bg-white/20 rounded-lg">
           <Sparkles size={20} className="text-yellow-300" />
        </div>
        <div>
           <h3 className="font-bold">智能医生助手</h3>
           <p className="text-xs text-blue-100">Powered by Gemini AI</p>
        </div>
      </div>

      {/* Messages Area */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50/50">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex max-w-[80%] gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${
                msg.role === 'user' ? 'bg-slate-200' : 'bg-primary-100'
              }`}>
                {msg.role === 'user' ? <User size={16} className="text-slate-600" /> : <Bot size={16} className="text-primary-600" />}
              </div>
              <div className={`p-4 rounded-2xl text-sm leading-relaxed shadow-sm whitespace-pre-wrap ${
                msg.role === 'user' 
                  ? 'bg-primary-600 text-white rounded-tr-none' 
                  : 'bg-white text-slate-700 border border-slate-100 rounded-tl-none'
              }`}>
                {msg.text}
              </div>
            </div>
          </div>
        ))}
        {isLoading && messages[messages.length - 1]?.role !== 'model' && (
          <div className="flex justify-start">
             <div className="flex max-w-[80%] gap-3">
               <div className="w-8 h-8 rounded-full bg-primary-100 flex items-center justify-center flex-shrink-0">
                 <Bot size={16} className="text-primary-600" />
               </div>
               <div className="bg-white p-4 rounded-2xl rounded-tl-none border border-slate-100 shadow-sm flex items-center gap-2">
                 <div className="w-2 h-2 bg-primary-400 rounded-full animate-bounce"></div>
                 <div className="w-2 h-2 bg-primary-400 rounded-full animate-bounce delay-100"></div>
                 <div className="w-2 h-2 bg-primary-400 rounded-full animate-bounce delay-200"></div>
               </div>
             </div>
          </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white border-t border-slate-100">
        <div className="relative">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyPress}
            placeholder="输入您的问题，例如：'尿酸450需要吃药吗？'"
            className="w-full pl-4 pr-12 py-4 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-primary-500 focus:bg-white transition-all shadow-inner"
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || isLoading}
            className="absolute right-2 top-2 p-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors shadow-md"
          >
            <Send size={20} />
          </button>
        </div>
        <p className="text-xs text-center text-slate-400 mt-2">
          AI 建议仅供参考，不能替代专业医疗诊断。
        </p>
      </div>
    </div>
  );
};

export default AIChat;

